'use server'

import { cookies } from 'next/headers'
import { revalidatePath } from 'next/cache'

export async function toggleNotifications() {
  const cookieStore = await cookies()

  // Read the current preference (default to 'on')
  const current = cookieStore.get('notifications')?.value ?? 'on'

  // Toggle it
  const next = current === 'on' ? 'off' : 'on'

  // Persist the new preference
  cookieStore.set('notifications', next, {
    httpOnly: true,
    sameSite: 'lax',
    path: '/',
    // No maxAge → session cookie (expires when browser closes)
  })

  // Revalidate the current page so the UI reflects the new state
  revalidatePath('/')
}

