import { cookies } from 'next/headers'
import { toggleNotifications } from './actions'

export default async function Home() {
  const cookieStore = await cookies()
  const notificationsEnabled = (cookieStore.get('notifications')?.value ?? 'on') === 'on'

  return (
    <main style={{ fontFamily: 'system-ui, sans-serif', padding: '2rem' }}>
      <h1>Settings</h1>

      <form action={toggleNotifications}>
        <p>
          Notifications:{' '}
          <strong>{notificationsEnabled ? 'On' : 'Off'}</strong>
        </p>

        <button type="submit">
          Turn {notificationsEnabled ? 'Off' : 'On'}
        </button>
      </form>
    </main>
  )
}

